SELECT storage_number, data_type
FROM aeronautical_data
WHERE strftime('%Y', revision_date) = '2022';

SELECT storage_number, boundary_type
FROM airspace_boundaries
WHERE boundary_type = 'vertical';

SELECT COUNT(*)
FROM aeronautical_data
WHERE data_type = 'airspace';

SELECT obstacle_type
FROM obstacles
WHERE storage_number = '1';

SELECT COUNT(*) AS number_of_man_made_obstacles
FROM obstacles
WHERE obstacle_type = 'man-made';

SELECT data_type, MIN(data_validity_start_date) AS earliest_validity_start
FROM aeronautical_data
GROUP BY data_type;

SELECT aid_type, location
FROM navigation_aids
WHERE aid_type = 'VOR';

SELECT location
FROM navigation_aids
WHERE storage_number = '1';
